INSERT INTO livros VALUES(33,'É ASSIM QUE ACABA','ROMANCE','COOLEN HOVER',55,'eassimqueacaba.jpg','A descrição oficial resume a história de Lily Bloom, uma mulher que supera uma infância difícil para abrir o próprio negócio em Boston, mas se vê em um relacionamento abusivo com o neurocirurgião Ryle, enquanto lida com o retorno de seu primeiro amor, Atlas.','assimqueacaba','assim.pdf');
INSERT INTO livros VALUES(34,'O EXORCISTA','TERROR','WILLIAM PETER BLATTY',75,'oExorcista.jpg','DESCRICAO','oExorcista','oExorcista.pdf');
INSERT INTO livros VALUES(35,'A HIPOTESE DO AMOR','ROMANCE','ALI HAZELWOOD',45,'A HIPOTESE DO AMOR.jpg','Quando um namoro de mentira entre cientistas encontra a irresistível força da atração, todas as teorias cuidadosamente calculadas sobre o amor são postas à prova.Com personagens cativantes e diálogos ','aHipoteseDoAMor','ahistoriadonosso.pdf');
INSERT INTO livros VALUES(37,'BRIDGENTON O VISCONDE QUE ME AMAVA','ROMANCE','JULIA QUINN',40,'oviscondequemeamava.jpg','A trama de O Visconde que Me Amava acompanha Anthony Bridgerton, o solteiro mais cobiçado de Londres. Assombrado por um trauma do passado e acreditando que morrerá jovem (assim como seu pai), ele decide se casar apenas por dever, escolhendo uma esposa por quem nunca se apaixonará.','visconde','oVisconde.pdf');
INSERT INTO livros VALUES(39,'TUDO QUE DEIXAMOS INACABADO','ROMANCE','REBECCA YARROS',35,'Tudoquedeixamos.jpg','Aos 28 anos, Georgia Stanton é obrigada a recomeçar a vida depois de um doloroso divórcio. Ao voltar para a casa da família no Colorado, ela se vê cara a cara com o autor best-seller Noah Harrison, que está na cidade para fechar um contrato e terminar o último livro da bisavó dela, uma famosa escritora. Ele é tão arrogante em pessoa quanto nas entrevistas, e Georgia não concorda que ele seja a escolha perfeita para essa tarefa.','tudo','tudoquenostem.pdf');
INSERT INTO livros VALUES(40,'A CULPA É DAS ESTRELAS','ROMANCE','JOHN GREEN',35,'aculpaedasestrelas.jpg','A Culpa É das Estrelas é o sexto romance de John Green, publicado em janeiro de 2012.','aCulpaEstrela','estrelas.pdf');
INSERT INTO livros VALUES(41,'HISTÓRIAS EXTRAORDINÁRIAS','TERROR','EDGAR ALLAN POE',65,'edganallanpoe.jpg','Nos últimos dois séculos, o nome de Edgar Allan Poe se tornou sinônimo de histórias de mistério, seja o suspense detetivesco (seu personagem Auguste Dupin inspirou a criação de ninguém menos que Sherlock Holmes), sejam as narrativas de teor sobrenatural, chegando a flertar em alguns textos com a ficção científica.','historietasa','historia.pdf');
INSERT INTO livros VALUES(42,'A MARCA DO ZORRO','AVENTURA','JOHNSTON MCULLEY',65,'amarcardozorro.jpg','Livro que deu origem ao personagem Zorro.Conta a história do jovem fidalgo Don Diego Vega e as aventuras da maldição de capistrano. Uma história cativante que prenderá o leitor até o final do livro.','marcaDoZorro','marcaDoZorro.pdf');
INSERT INTO livros VALUES(43,'A CRÔNICAS DE NARNIA','AVENTURA','CS.  LEWIS',65,'As cronicas de narnoa.jpg','As Crônicas de Nárnia é uma famosa série de sete livros de fantasia épica escrita pelo autor britânico C. S. Lewis. A obra narra as aventuras de crianças no nosso mundo que são transportadas para o mágico mundo de Nárnia, onde enfrentam forças do mal ao lado do grande leão Aslan','asCronicasDeNarnia','cronicas.pdf');
INSERT INTO livros VALUES(44,'O CONDE DE MONTE CRISTO','AVENTURA','ALEXANDRE DUMAS',25,'O Conde de Monte Criato.jpg','O Conde de Monte Cristo é um romance de aventura francês escrito por Alexandre Dumas, em colaboração com Auguste Maquet, concluído em 1844. Inicialmente publicado como folhetim de 1844 a 1846.','monteCristo','montecristo.pdf');
INSERT INTO livros VALUES(45,'ANNA KADABRA - O CLUBE DA LUA CHEIA','FANTASIA','DAVID SIERRA LISTON',30,'anakadarba.jpg','Anna Kadabra - O Clube da Lua Cheia é o primeiro volume da popular série infantil escrita por Pedro Mañas e ilustrada por David Sierra Listón. O livro conta a história de uma garota comum que se muda para a misteriosa vila de Moonville e descobre que, na verdade, possui poderes mágicos.','anakadabra','anakadabra.pdf');
INSERT INTO livros VALUES(46,'AVATAR: O ULTIMO MESTRE DO AR','FANTASIA','F.C YEE',40,'avatar.jpg','O universo de Avatar: O Último Mestre do Ar não tem apenas livros em formato de quadrinhos (que dão continuidade à série de TV), mas também romances oficiais que expandem o passado de Avatares anteriores.','avatar','avatar.pdf');
INSERT INTO livros VALUES(47,'IT- A COISA','TERROR','STEPHEN KING',106,'itAcoisa.jpg','It é um romance de terror de 1986 do autor estadunidense Stephen King. Foi seu 22º livro e seu 17º romance escrito em seu próprio nome. A história segue as experiências de sete crianças, que são aterrorizadas por uma entidade maligna que explora os medos de suas vítimas para se disfarçar enquanto caçam suas presas.','itACoisa','itacoisa.pdf');
INSERT INTO livros VALUES(48,'O DIARIO DE UMA PRINCESA DESASTRADA','FANTASIA','MAIDY LACERDA',44,'odiariodeumcafajetse.jpg','Princesas são sempre graciosas, né? Mas a princesa Amora Maria Florentina de Florentia não. Na verdade, ninguém pode saber que ela é uma princesa e tem que fingir que é apenas a Florentina: a menina desastrada da escola que ninguém gosta! E, para piorar, ela é um poço de derrotas.','princesa','princesa.pdf');
INSERT INTO livros VALUES(49,'O GATO QUE AMAVA LIVROS','FANTASIA','SOSUKE NATSUKAWA',38,'ogatoqueamavalivros.jpg','Uma história sobre encontrar a própria coragem, sobre cuidar de si e dos outros – e sobre o imenso poder da literatura. A livraria Natsuke era uma loja de livros usados quase fora da cidade. Quem passava por lá via estantes que iam do chão até o teto, abarrotadas das mais maravilhosas obras literárias.','oGatoQueAmava','oGatoQueLia.pdf');
INSERT INTO livros VALUES(50,'DUNA','FICCAO','FRANK  HEBERT',75,'capa-livro-duna.jpg','Duna é um romance de ficção científica do escritor estadunidense Frank Herbert, publicado originalmente pela editora Chilton Books nos Estados Unidos em 1965. Vencedor do prêmio Hugo de 1966, Duna é considerado o livro de ficção científica mais vendido de todos os tempos.','duna','duna.pdf');
INSERT INTO livros VALUES(51,'EXPIRAÇÃO','FICCAO','TED CHIANG',50,'expiracao-ted-chiang.jpg','Em nova coletânea, um dos principais autores contemporâneos de ficção científica continua a estimular reflexões sobre as grandes questões da humanidadeDepois um dos contos de História da sua vida ','expiracao','extracao.pdf');
INSERT INTO livros VALUES(52,'GUERRA DO VELHO','FICCAO','JOHN SCALZI',64,'guerra-do-velho-john-scalzi.jpg','A humanidade finalmente chegou à era das viagens interestelares. A má notícia é que há poucos planetas habitáveis disponíveis – e muitos alienígenas lutando por eles.','guerraDoVelho','guerraDoVelho.pdf');
INSERT INTO livros VALUES(53,'O FIM DA MORTE','FICCAO','CIXIN LIU',80,'o-problema-dos-tres-corpos-cixin-liu.jpg','Iintitulado O Fim da Morte no Brasil, A Morte Eterna em Portugal e Death''s End em inglês, é o terceiro e último romance de ficção científica da série O Passado do Planeta Terra ou Lembranças do Passado da Terra do escritor chinês Liu Cixin','oFimDaMorte','ofimmorte.pdf');
INSERT INTO livros VALUES(56,'PERDIDO EM MARTE','FICCAO','ANDY WEIR',190,'perdido-em-marte-andy-weir.jpg','Perdido em Marte (originalmente intitulado The Martian) é um aclamado livro de ficção científica hard escrito por Andy Weir. A obra mistura suspense de sobrevivência com explicações científicas reais','perdido','perdidoEmMarte.pdf');
