PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE usuarios (id INTEGER PRIMARY KEY AUTOINCREMENT, nome TEXT, email TEXT, senha TEXT, role TEXT);
CREATE TABLE livros (id INTEGER PRIMARY KEY AUTOINCREMENT, nome TEXT, genero TEXT, autor TEXT, preco INTEGER, imagem TEXT, descricao TEXT, nome_arquivo TEXT, url_arquivo TEXT);
CREATE TABLE favoritos (id INTEGER PRIMARY KEY AUTOINCREMENT, id_usuario INTEGER, id_livro INTEGER);
DELETE FROM sqlite_sequence;
CREATE UNIQUE INDEX usuario_livro_unico ON favoritos (id_usuario, id_livro);
COMMIT;
